FormulationConfig = {}
FormulationConfig.Formulation = {}

function FormulationConfig:init(config)
    for _, recipe in pairs(config) do
        local data = {}
        data.Id = tonumber(recipe.Id)
        data.ItemId = tonumber(recipe.ItemId)
        data.Count = tonumber(recipe.Count)
        data.MaterialsId =StringUtil.split(recipe.Materials,"#")
        self.Formulation[data.Id]=data
        --print(json.encode(self.Formulation[data.Id]))
    end
end

function FormulationConfig:getFormulationById(Id)
    return self.Formulation[tonumber(Id)]
end

return FormulationConfig